 1	import * as React from 'react';
 2	import { Flex } from '@patternfly/react-core';
 3	import { Popover } from '@patternfly/react-core';
 4	import { Button } from '@patternfly/react-core';
 5	import {
 6	  ExclamationCircleIcon,
 7	  ExclamationTriangleIcon,
 8	} from '@patternfly/react-icons';
 9	import { PoolUtilizationPopoverContent } from '../dashboards/persistent-internal/pool-utilization-card/PoolUtilizationPopoverContent';
10	import { StoragePoolTableData } from '../dashboards/persistent-internal/pool-utilization-card/types';
11	
12	export const PoolUtilizationDisplay: React.FC<{
13	  pool: StoragePoolTableData;
14	  usedCapacityDisplay: string;
15	  utilizationPercentage: number;
16	  isCritical: boolean;
17	  isWarning: boolean;
18	  needsAttention: boolean;
19	  totalCapacity: string;
20	}> = ({
21	  pool,
22	  usedCapacityDisplay,
23	  utilizationPercentage,
24	  isCritical,
25	  isWarning,
26	  needsAttention,
27	  totalCapacity,
28	}) => {
29	  if (!needsAttention) {
30	    return <>{usedCapacityDisplay}</>;
31	  }
32	
33	  return (
34	    <Popover
35	      aria-label="Pool utilization information"
36	      bodyContent={
37	        <PoolUtilizationPopoverContent
38	          pool={
39	            {
40	              ...pool,
41	              utilization: utilizationPercentage,
42	              usedCapacity: usedCapacityDisplay,
43	              totalCapacity: totalCapacity,
44	              critical: isCritical,
45	              warning: isWarning,
46	            } as StoragePoolTableData
47	          }
48	        />
49	      }
50	      hasAutoWidth
51	      triggerAction="hover"
52	    >
53	      <Button variant="link" className="pf-v5-u-text-align-left pf-v6-u-w-100">
54	        <Flex
55	          alignItems={{ default: 'alignItemsCenter' }}
56	          spaceItems={{ default: 'spaceItemsSm' }}
57	        >
58	          {isCritical ? (
59	            <ExclamationCircleIcon className="pf-v5-u-danger-color-100" />
60	          ) : (
61	            <ExclamationTriangleIcon className="pf-v5-u-warning-color-100" />
62	          )}
63	          <span className="pf-v5-u-word-break-break-word">
64	            {usedCapacityDisplay} ({utilizationPercentage.toFixed(1)}%)
65	          </span>
66	        </Flex>
67	      </Button>
68	    </Popover>
69	  );
70	};

